# --- Token Validation Utilities ---

def extract_bearer_token():
    """Extract Bearer token from Authorization header or query parameter."""
    auth_header = request.headers.get('Authorization', '')
    if auth_header.startswith('Bearer '):
        return auth_header[7:].strip()

    # Fallback: check query parameter (not recommended for production)
    token = request.args.get('access_token')
    if token:
        return token.strip()

    # Fallback: check form body
    token = request.form.get('access_token')
    if token:
        return token.strip()

    return None


def validate_token(token_string):
    """Validate an access token and return the AccessToken object if valid."""
    if not token_string:
        return None, 'missing_token', 'No access token provided.'

    access_token = AccessToken.query.filter_by(token=token_string).first()

    if access_token is None:
        log_token_action('rejected', ip_address=request.remote_addr,
                         endpoint=request.path, details='Token not found in database')
        return None, 'invalid_token', 'The access token is invalid.'

    if access_token.is_revoked:
        log_token_action('rejected', token_id=access_token.id, ip_address=request.remote_addr,
                         endpoint=request.path, details='Token has been revoked')
        return None, 'invalid_token', 'The access token has been revoked.'

    if access_token.is_expired():
        log_token_action('expired', token_id=access_token.id, ip_address=request.remote_addr,
                         endpoint=request.path, details='Token has expired')
        return None, 'invalid_token', 'The access token has expired.'

    # Verify the client is still active
    if not access_token.client.is_active:
        log_token_action('rejected', token_id=access_token.id,
                         client_id=access_token.client.client_id,
                         ip_address=request.remote_addr, endpoint=request.path,
                         details='Client is deactivated')
        return None, 'invalid_token', 'The client associated with this token is no longer active.'

    log_token_action('validated', token_id=access_token.id,
                     client_id=access_token.client.client_id,
                     ip_address=request.remote_addr, endpoint=request.path)

    return access_token, None, None


def log_token_action(action, token_id=None, client_id=None, ip_address=None, endpoint=None, details=None):
    """Log a token-related action to the audit log."""
    try:
        log_entry = TokenAuditLog(
            action=action,
            token_id=token_id,
            client_id=client_id,
            ip_address=ip_address,
            endpoint=endpoint,
            details=details
        )
        db.session.add(log_entry)
        db.session.commit()
    except Exception:
        db.session.rollback()


