def require_oauth(*required_scopes):
    """
    Decorator to protect API endpoints with OAuth 2.0 token validation.

    Usage:
        @require_oauth()                     # Just requires a valid token
        @require_oauth('read')               # Requires 'read' scope
        @require_oauth('read', 'write')      # Requires both 'read' AND 'write' scopes
    """
    def decorator(f):
        @functools.wraps(f)
        def decorated_function(*args, **kwargs):
            token_string = extract_bearer_token()

            if not token_string:
                return jsonify({
                    'error': 'missing_token',
                    'error_description': 'An access token is required to access this resource.'
                }), 401, {
                    'WWW-Authenticate': 'Bearer realm="api"'
                }

            access_token, error, error_description = validate_token(token_string)

            if error:
                status_code = 401
                www_auth = f'Bearer realm="api", error="{error}", error_description="{error_description}"'
                return jsonify({
                    'error': error,
                    'error_description': error_description
                }), status_code, {
                    'WWW-Authenticate': www_auth
                }

            # Check scopes
            if required_scopes:
                if not access_token.has_scopes(required_scopes):
                    missing = set(required_scopes) - set(access_token.get_scopes())
                    log_token_action('rejected', token_id=access_token.id,
                                     client_id=access_token.client.client_id,
                                     ip_address=request.remote_addr,
                                     endpoint=request.path,
                                     details=f'Insufficient scope. Missing: {missing}')
                    return jsonify({
                        'error': 'insufficient_scope',
                        'error_description': f'This resource requires the following scopes: {", ".join(required_scopes)}',
                        'required_scopes': list(required_scopes),
                        'granted_scopes': access_token.get_scopes()
                    }), 403, {
                        'WWW-Authenticate': f'Bearer realm="api", error="insufficient_scope", scope="{" ".join(required_scopes)}"'
                    }

            # Store token info in flask g for use in the endpoint
            g.current_token = access_token
            g.current_client = access_token.client
            g.current_user_id = access_token.user_id
            g.token_scopes = access_token.get_scopes()

            return f(*args, **kwargs)

        return decorated_function
    return decorator


