@app.route('/oauth/token', methods=['POST'])
def issue_token():
    """
    Issue a new access token (client_credentials grant or refresh_token grant).
    """
    grant_type = request.form.get('grant_type')

    if grant_type == 'client_credentials':
        return handle_client_credentials()
    elif grant_type == 'refresh_token':
        return handle_refresh_token()
    else:
        return jsonify({
            'error': 'unsupported_grant_type',
            'error_description': 'Only client_credentials and refresh_token grant types are supported.'
        }), 400


def handle_client_credentials():
    """Handle client_credentials grant type."""
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')

    # Also support HTTP Basic Auth for client authentication
    if not client_id or not client_secret:
        auth = request.authorization
        if auth:
            client_id = auth.username
            client_secret = auth.password

    if not client_id or not client_secret:
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Client credentials are required.'
        }), 401

    client = OAuthClient.query.filter_by(client_id=client_id).first()

    if not client or client.client_secret != client_secret:
        log_token_action('rejected', client_id=client_id,
                         ip_address=request.remote_addr,
                         details='Invalid client credentials')
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Invalid client credentials.'
        }), 401

    if not client.is_active:
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Client is deactivated.'
        }), 401

    # Determine scopes
    requested_scopes = request.form.get('scope', '').split()
    allowed_scopes = client.get_allowed_scopes()

    if requested_scopes:
        # Validate requested scopes against allowed scopes
        invalid_scopes = set(requested_scopes) - set(allowed_scopes)
        if invalid_scopes:
            return jsonify({
                'error': 'invalid_scope',
                'error_description': f'The following scopes are not allowed: {", ".join(invalid_scopes)}'
            }), 400
        granted_scopes = requested_scopes
    else:
        granted_scopes = allowed_scopes

    # Generate tokens
    token_string = secrets.token_urlsafe(48)
    refresh_token_string = secrets.token_urlsafe(48)
    expires_in = 3600  # 1 hour

    access_token = AccessToken(
        token=token_string,
        client_id=client.id,
        scopes=' '.join(granted_scopes),
        expires_at=datetime.now(timezone.utc) + timedelta(seconds=expires_in)
    )
    db.session.add(access_token)
    db.session.flush()

    refresh_token = RefreshToken(
        token=refresh_token_string,
        access_token_id=access_token.id,
        client_id=client.id
    )
    db.session.add(refresh_token)
    db.session.commit()

    log_token_action('issued', token_id=access_token.id, client_id=client.client_id,
                     ip_address=request.remote_addr,
                     details=f'Scopes: {" ".join(granted_scopes)}')

    return jsonify({
        'access_token': token_string,
        'token_type': 'Bearer',
        'expires_in': expires_in,
        'refresh_token': refresh_token_string,
        'scope': ' '.join(granted_scopes)
    }), 200


def handle_refresh_token():
    """Handle refresh_token grant type."""
    refresh_token_string = request.form.get('refresh_token')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')

    if not client_id or not client_secret:
        auth = request.authorization
        if auth:
            client_id = auth.username
            client_secret = auth.password

    if not refresh_token_string:
        return jsonify({
            'error': 'invalid_request',
            'error_description': 'refresh_token is required.'
        }), 400

    if not client_id or not client_secret:
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Client credentials are required.'
        }), 401

    client = OAuthClient.query.filter_by(client_id=client_id).first()
    if not client or client.client_secret != client_secret or not client.is_active:
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Invalid client credentials.'
        }), 401

    refresh_token = RefreshToken.query.filter_by(token=refresh_token_string, client_id=client.id).first()

    if not refresh_token or refresh_token.is_revoked:
        return jsonify({
            'error': 'invalid_grant',
            'error_description': 'Invalid or revoked refresh token.'
        }), 400

    # Revoke old tokens
    old_access_token = refresh_token.access_token
    old_access_token.is_revoked = True
    refresh_token.is_revoked = True

    # Issue new tokens
    token_string = secrets.token_urlsafe(48)
    new_refresh_token_string = secrets.token_urlsafe(48)
    expires_in = 3600

    new_access_token = AccessToken(
        token=token_string,
        client_id=client.id,
        user_id=old_access_token.user_id,
        scopes=old_access_token.scopes,
        expires_at=datetime.now(timezone.utc) + timedelta(seconds=expires_in)
    )
    db.session.add(new_access_token)
    db.session.flush()

    new_refresh_token = RefreshToken(
        token=new_refresh_token_string,
        access_token_id=new_access_token.id,
        client_id=client.id
    )
    db.session.add(new_refresh_token)
    db.session.commit()

    log_token_action('issued', token_id=new_access_token.id, client_id=client.client_id,
                     ip_address=request.remote_addr,
                     details=f'Refreshed from token {old_access_token.id}')

    return jsonify({
        'access_token': token_string,
        'token_type': 'Bearer',
        'expires_in': expires_in,
        'refresh_token': new_refresh_token_string,
        'scope': old_access_token.scopes
    }), 200


@app.route('/oauth/revoke', methods=['POST'])
def revoke_token():
    """Revoke an access token or refresh token."""
    token_string = request.form.get('token')
    token_type_hint = request.form.get('token_type_hint', 'access_token')

    if not token_string:
        return jsonify({
            'error': 'invalid_request',
            'error_description': 'token parameter is required.'
        }), 400

    # Client authentication
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')

    if not client_id or not client_secret:
        auth = request.authorization
        if auth:
            client_id = auth.username
            client_secret = auth.password

    if not client_id or not client_secret:
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Client credentials are required.'
        }), 401

    client = OAuthClient.query.filter_by(client_id=client_id).first()
    if not client or client.client_secret != client_secret:
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Invalid client credentials.'
        }), 401

    revoked = False

    if token_type_hint == 'refresh_token':
        refresh_token = RefreshToken.query.filter_by(token=token_string, client_id=client.id).first()
        if refresh_token:
            refresh_token.is_revoked = True
            refresh_token.access_token.is_revoked = True
            revoked = True
    else:
        access_token = AccessToken.query.filter_by(token=token_string, client_id=client.id).first()
        if access_token:
            access_token.is_revoked = True
            if access_token.refresh_token:
                access_token.refresh_token.is_revoked = True
            revoked = True

    if revoked:
        db.session.commit()
        log_token_action('revoked', client_id=client.client_id,
                         ip_address=request.remote_addr,
                         details=f'Token type: {token_type_hint}')

    # RFC 7009: always return 200, even if token was not found
    return jsonify({'status': 'ok'}), 200


@app.route('/oauth/introspect', methods=['POST'])
def introspect_token():
    """Token introspection endpoint (RFC 7662)."""
    token_string = request.form.get('token')

    if not token_string:
        return jsonify({'active': False}), 200

    # Client authentication for introspection
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')

    if not client_id or not client_secret:
        auth = request.authorization
        if auth:
            client_id = auth.username
            client_secret = auth.password

    if not client_id or not client_secret:
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Client credentials are required for introspection.'
        }), 401

    client = OAuthClient.query.filter_by(client_id=client_id).first()
    if not client or client.client_secret != client_secret:
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Invalid client credentials.'
        }), 401

    access_token = AccessToken.query.filter_by(token=token_string).first()

    if not access_token or not access_token.is_valid():
        return jsonify({'active': False}), 200

    expires_at = access_token.expires_at
    if expires_at.tzinfo is None:
        expires_at = expires_at.replace(tzinfo=timezone.utc)

    return jsonify({
        'active': True,
        'scope': access_token.scopes,
        'client_id': access_token.client.client_id,
        'token_type': 'Bearer',
        'exp': int(expires_at.timestamp()),
        'iat': int(access_token.created_at.replace(tzinfo=timezone.utc).timestamp()) if access_token.created_at.tzinfo is None else int(access_token.created_at.timestamp()),
        'sub': access_token.user_id,
    }), 200


